73	pub fn upload_state_after_attempt(previous: UploadState, success: bool) -> UploadState {
74	    if success {
75	        UploadState::Success
76	    } else if matches!(previous, UploadState::Uploading) {
77	        UploadState::Failed
78	    } else {
79	        previous
80	    }
81	}
