30	            strategy: "require_existing".to_string(),
31	            key_file,
32	            key_length: 32,
33	        };
34	        let result = FieldCrypto::load_or_bootstrap(&cfg).await;
35	        assert!(result.is_err());
36	    }
37	
38	    #[tokio::test]
39	    async fn invalid_strategy_is_rejected() {
40	        let cfg = KeyBootstrapConfig {
41	            strategy: "fallback_only".to_string(),
42	            key_file: "/tmp/ignored-key.json".to_string(),
43	            key_length: 32,
44	        };
45	        let result = FieldCrypto::load_or_bootstrap(&cfg).await;
46	        assert!(result.is_err());
47	    }
48	}
49	
50	#[derive(Debug, Serialize, Deserialize)]
51	struct KeyRingDisk {
52	    active_key_version: String,
53	    keys: HashMap<String, String>,
54	}
55	
56	impl FieldCrypto {
57	    pub async fn load_or_bootstrap(cfg: &KeyBootstrapConfig) -> Result<Self, Box<dyn std::error::Error>> {
58	        if cfg.strategy != "generate_if_missing" && cfg.strategy != "require_existing" {
59	            return Err("security.key_bootstrap.strategy must be generate_if_missing or require_existing".into());
60	        }
61	
62	        let key_path = Path::new(&cfg.key_file);
63	        if let Some(parent) = key_path.parent() {
64	            fs::create_dir_all(parent).await?;
65	        }
66	
67	        if !key_path.exists() && cfg.strategy == "generate_if_missing" {
68	            let mut bytes = vec![0u8; cfg.key_length];
69	            rand::thread_rng().fill_bytes(&mut bytes);
70	            let encoded = base64::engine::general_purpose::STANDARD.encode(bytes);
71	            let mut keys = HashMap::new();
72	            keys.insert("v1".to_string(), encoded);
73	            let disk = KeyRingDisk {
74	                active_key_version: "v1".to_string(),
75	                keys,
76	            };
77	            fs::write(key_path, serde_json::to_string_pretty(&disk)?).await?;
78	        }
79	
80	        if !key_path.exists() {
81	            return Err("encryption key material not found; startup aborted".into());
82	        }
83	
84	        let raw = fs::read_to_string(key_path).await?;
85	        let parsed = if raw.trim_start().starts_with('{') {
86	            serde_json::from_str::<KeyRingDisk>(&raw)?
87	        } else {
88	            let mut keys = HashMap::new();
89	            keys.insert("v1".to_string(), raw.trim().to_string());
90	            let disk = KeyRingDisk {
91	                active_key_version: "v1".to_string(),
92	                keys,
93	            };
94	            fs::write(key_path, serde_json::to_string_pretty(&disk)?).await?;
95	            disk
96	        };
97	
98	        let mut decoded = HashMap::new();
99	        for (version, key_b64) in parsed.keys {
100	            let bytes = base64::engine::general_purpose::STANDARD
101	                .decode(key_b64.trim())
102	                .map_err(|_| "invalid key in keyring")?;
103	            if bytes.len() != 32 {
104	                return Err("key length must be 32 bytes".into());
105	            }
106	            decoded.insert(version, bytes);
107	        }
108	
109	        if !decoded.contains_key(&parsed.active_key_version) {
110	            return Err("active key version missing from keyring".into());
111	        }
112	
113	        Ok(Self {
114	            active_key_version: parsed.active_key_version,
115	            keys: decoded,
116	        })
117	    }
118	
119	    pub fn active_key_version(&self) -> &str {
120	        &self.active_key_version
121	    }
122	
123	    pub fn encrypt(&self, plain: &str) -> Result<String, ApiError> {
124	        let key = self
125	            .keys
126	            .get(&self.active_key_version)
127	            .ok_or(ApiError::Internal)?;
128	        let cipher = Aes256Gcm::new_from_slice(key).map_err(|_| ApiError::Internal)?;
129	
130	        let mut nonce_bytes = [0u8; 12];
131	        rand::thread_rng().fill_bytes(&mut nonce_bytes);
132	        let nonce = Nonce::from_slice(&nonce_bytes);
133	        let encrypted = cipher
134	            .encrypt(nonce, plain.as_bytes())
135	            .map_err(|_| ApiError::Internal)?;
136	
137	        Ok(format!(
138	            "{}:{}:{}",
139	            self.active_key_version,
140	            base64::engine::general_purpose::STANDARD.encode(nonce_bytes),
141	            base64::engine::general_purpose::STANDARD.encode(encrypted)
142	        ))
143	    }
144	
145	    pub fn decrypt(&self, cipher_text: &str) -> Result<String, ApiError> {
146	        let mut parts = cipher_text.split(':');
147	        let version = parts.next().ok_or(ApiError::Internal)?;
148	        let nonce_b64 = parts.next().ok_or(ApiError::Internal)?;
149	        let data_b64 = parts.next().ok_or(ApiError::Internal)?;
150	        if parts.next().is_some() {
151	            return Err(ApiError::Internal);
152	        }
153	
154	        let key = self.keys.get(version).ok_or(ApiError::Internal)?;
155	        let nonce_bytes = base64::engine::general_purpose::STANDARD
156	            .decode(nonce_b64)
157	            .map_err(|_| ApiError::Internal)?;
158	        let encrypted = base64::engine::general_purpose::STANDARD
159	            .decode(data_b64)
160	            .map_err(|_| ApiError::Internal)?;
161	
162	        let cipher = Aes256Gcm::new_from_slice(key).map_err(|_| ApiError::Internal)?;
163	        let decrypted = cipher
164	            .decrypt(Nonce::from_slice(&nonce_bytes), encrypted.as_ref())
165	            .map_err(|_| ApiError::Internal)?;
166	        String::from_utf8(decrypted).map_err(|_| ApiError::Internal)
167	    }
168	
169	    pub fn hash_for_lookup(value: &str) -> String {
170	        hex::encode(Sha256::digest(value.trim().as_bytes()))
171	    }
172	}
