        let ciphertext = crypto.encrypt("sensitive visit note").expect("encrypt");
        let tampered = format!("{}X", ciphertext);
        assert!(crypto.decrypt(&tampered).is_err());
        let _ = std::fs::remove_file(&key_file);
    }

    #[test]
