    fn pagination_boundary_large_offset() {
        let limit: i64 = 100;
        let offset: i64 = 999_999;
        let safe_limit = limit.clamp(1, 100);
        let safe_offset = offset.max(0);
        assert_eq!(safe_limit, 100);
        assert_eq!(safe_offset, 999_999);
    }

